import React, { useState } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

// --- HORIZONTAL WIG STORE COMPONENT ---
const WigStore = () => {
  const gold = '#D4AF37';
  const fancyFont = "'Playfair Display', 'Georgia', serif";

  const categories = [
    {
      type: "Human Hair",
      note: "100% authentic. Dyeable, heat-styleable, and lasts years.",
      items: [
        { name: "Raw Cambodian", price: "85,000", desc: "14-inch frontal unit. natural luster." },
        { name: "Luxury Bone Straight", price: "120,000", desc: "Super double drawn premium." }
      ]
    },
    {
      type: "Premium Fibre",
      note: "High-heat resistant. Pre-styled luxury that holds its shape.",
      items: [
        { name: "Sleek Straight", price: "35,000", desc: "Heat resistant up to 180°C." },
        { name: "Kinky Straight", price: "40,000", desc: "Mimics blown-out natural hair." }
      ]
    },
    {
      type: "Hair Blend",
      note: "Human hair & fibre mix. Affordable and holds curls longer.",
      items: [
        { name: "Piano Wavy", price: "25,000", desc: "24-inch high-octane volume." },
        { name: "Deep Wave Blend", price: "28,000", desc: "Ready-to-wear glueless system." }
      ]
    }
  ];

  return (
    <div style={{ 
      display: 'grid', 
      gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', 
      gap: '20px', 
      alignItems: 'start' 
    }}>
      {categories.map((cat) => (
        <div key={cat.type} style={{ 
          display: 'flex', 
          flexDirection: 'column', 
          border: `1px solid ${gold}33`, 
          backgroundColor: '#050505',
          borderRadius: '4px',
          paddingBottom: '20px'
        }}>
          
          {/* CATEGORY HEADER */}
          <div style={{ padding: '25px', borderBottom: `1px solid ${gold}22`, textAlign: 'center', marginBottom: '20px' }}>
            <h3 style={{ color: gold, fontFamily: fancyFont, fontSize: '1.6rem', margin: '0 0 10px 0' }}>{cat.type}</h3>
            <p style={{ color: '#777', fontSize: '0.8rem', fontStyle: 'italic', lineHeight: '1.4' }}>{cat.note}</p>
          </div>

          {/* VERTICAL PRODUCT LIST */}
          <div style={{ padding: '0 15px' }}>
            {cat.items.map((item) => (
              <div key={item.name} style={{ textAlign: 'center', marginBottom: '40px', borderBottom: '1px solid #111', paddingBottom: '20px' }}>
                <div style={{ width: '100%', height: '300px', backgroundColor: '#0a0a0a', marginBottom: '15px', borderRadius: '2px' }}>
                   <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#222', fontSize: '0.7rem' }}>
                     [PRODUCT IMAGE]
                   </div>
                </div>
                <h4 style={{ color: gold, fontFamily: fancyFont, fontSize: '1.2rem', margin: '5px 0' }}>{item.name}</h4>
                <p style={{ color: '#555', fontSize: '0.75rem', margin: '10px 0' }}>{item.desc}</p>
                <div style={{ color: gold, fontWeight: 'bold', fontSize: '1.1rem' }}>₦{item.price}</div>
                <button style={{ 
                  marginTop: '15px', background: 'none', border: `1px solid ${gold}`, 
                  color: gold, padding: '10px 20px', cursor: 'pointer', fontSize: '0.7rem', letterSpacing: '1px' 
                }}>
                  ORDER ON WHATSAPP
                </button>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

// --- MAIN APP ---
function App() {
  const [activeCategory, setActiveCategory] = useState('Wigs');
  const gold = '#D4AF37';
  const fancyFont = "'Playfair Display', 'Georgia', serif";

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'Arial, sans-serif' }}>
      
      {/* NAV BAR */}
      <nav style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '30px 20px', borderBottom: '1px solid #111' }}>
        <img src={Logo} alt="Logo" style={{ height: '80px', marginBottom: '25px' }} />
        <div style={{ display: 'flex', gap: '25px', flexWrap: 'wrap', justifyContent: 'center' }}>
          {['Small Chops', 'Office Lunch', 'Wigs', 'About Us'].map((item) => (
            <button 
              key={item} 
              onClick={() => setActiveCategory(item)}
              style={{ 
                background: 'none', border: 'none', color: gold, fontSize: '0.7rem', cursor: 'pointer',
                letterSpacing: '2px', textTransform: 'uppercase', paddingBottom: '5px',
                borderBottom: activeCategory === item ? `2px solid ${gold}` : '2px solid transparent',
                opacity: activeCategory === item ? 1 : 0.4
              }}
            >
              {item}
            </button>
          ))}
        </div>
      </nav>

      {/* CONTENT */}
      <main style={{ padding: '40px 15px', maxWidth: '1300px', margin: '0 auto' }}>
        {activeCategory === 'Wigs' && (
          <div>
            <h2 style={{ color: gold, textAlign: 'center', fontSize: '2.5rem', fontFamily: fancyFont, marginBottom: '50px', fontStyle: 'italic' }}>
              The Hair Edit
            </h2>
            <WigStore />
          </div>
        )}
        {activeCategory === 'Small Chops' && <Menu />}
        {activeCategory === 'Office Lunch' && <Lunch />}
      </main>

    </div>
  );
}

export default App;
